    <script>
        document.addEventListener(""DOMContentLoaded"", function () {
            const roleSelect = document.getElementById(""roleSelect"");
            const studentIdField = document.getElementById(""studentIdField"");
            const staffIdField = document.getElementById(""staffIdField"");
            const departmentField = document.getElementById(""departmentField"");

            function updateFields() {
                const selectedRole = roleSelect.value;

                studentIdField.style.display = ""none"";
                staffIdField.style.display = ""none"";
                departmentField.style.display = ""none"";

                if (selectedRole === ""Student"") {
                    studentIdField.style.display = ""block"";
                } else if (selectedRole === ""Librarian"" || selectedRole === ""Lecturer"") {
                    staffIdField.style.display = ""block"";
                    departmentField.style.display = ""block"";
                }
            }

     ");
                WriteLiteral("       updateFields();\r\n            roleSelect.addEventListener(\"change\", updateFields);\r\n        });\r\n    </script>\r\n");
            }
            );
            WriteLiteral("\r\n");
        }
